constraints.constraint:
Enable RLS on ALL tenant-scoped tables: widget_view, future projection tables.
Use: ALTER TABLE table_name ENABLE ROW LEVEL SECURITY;
Apply to projection tables (read models), NOT event store (single-tenant per aggregate).

interface.pattern:
-- Enable RLS on widget_view projection table
ALTER TABLE widget_view ENABLE ROW LEVEL SECURITY;

-- Create tenant isolation policy
CREATE POLICY tenant_isolation ON widget_view
FOR ALL
USING (tenant_id = current_setting('app.tenant_id', true));

-- Create BRIN index for performance
CREATE INDEX idx_widget_view_tenant_id ON widget_view USING BRIN (tenant_id);

@Component
class TenantContextExecuteListener(
  private val tenantContext: TenantContext
) : DefaultExecuteListener() {

  override fun start(ctx: ExecuteContext) {
    val tenantId = tenantContext.current() ?: return // nullable for non-tenant queries
    ctx.dsl().execute("SET LOCAL app.tenant_id = ?", tenantId)
  }
}

test("RLS blocks cross-tenant access via direct SQL") {
  // Set session variable for Tenant A
  dataSource.connection.use { conn ->
    conn.createStatement().execute("SET LOCAL app.tenant_id = 'tenant-a'")

    // Query should only return Tenant A widgets
    val rs = conn.createStatement().executeQuery("SELECT * FROM widget_view")
    // Verify: only tenant-a widgets returned, tenant-b widgets blocked by RLS
  }
}
